import { cn } from '@/utils/cn';
import { BaseColorProps } from '@/type';
import { cva, VariantProps } from 'class-variance-authority';
import { Component, createUniqueId, mergeProps, Switch, Match } from 'solid-js';
import Loader from 'lucide-solid/icons/loader';

// Variants dùng DaisyUI classes (spinner, spinner-2, dots, ring, ball, bars, infinity)
const daisy_variants = cva('loading', {
  variants: {
    variant: {
      spinner: 'loading-spinner',
      'spinner-2': 'loading-spinner-2',
      dots: 'loading-dots',
      ring: 'loading-ring',
      ball: 'loading-ball',
      bars: 'loading-bars',
      infinity: 'loading-infinity',
    },
    size: {
      xs: 'loading-xs',
      sm: 'loading-sm',
      md: 'loading-md',
      lg: 'loading-lg',
      xl: 'loading-xl',
    },
  },
});

// Map size → CSS class cho SVG-based spinners
const svg_size_map = {
  xs: 'loading-svg-xs',
  sm: 'loading-svg-sm',
  md: 'loading-svg-md',
  lg: 'loading-svg-lg',
  xl: 'loading-svg-xl',
} as const;

// Map BaseColorProps → CSS variable của DaisyUI/Tailwind
const base_color_vars: Record<BaseColorProps, string> = {
  primary: 'var(--color-primary)',
  secondary: 'var(--color-secondary)',
  accent: 'var(--color-accent)',
  neutral: 'var(--color-neutral)',
  info: 'var(--color-info)',
  success: 'var(--color-success)',
  warning: 'var(--color-warning)',
  error: 'var(--color-error)',
};

/** Resolve color prop: nếu là BaseColorProps key thì map sang CSS var, còn lại dùng trực tiếp */
function resolveColor(color: string | undefined): string | undefined {
  if (!color) return undefined;
  return color in base_color_vars ? base_color_vars[color as BaseColorProps] : color;
}

type DaisyVariant = 'spinner' | 'spinner-2' | 'dots' | 'ring' | 'ball' | 'bars' | 'infinity';
type SvgVariant = 'spinner-3' | 'spinner-4' | 'spinner-5' | 'spinner-6';
type SizeKey = keyof typeof svg_size_map;

type LoadingProps = {
  variant?: DaisyVariant | SvgVariant;
  size?: SizeKey;
  /** Nhận BaseColorProps ('primary', 'error', ...) hoặc bất kỳ giá trị CSS color nào */
  color?: BaseColorProps | string;
  class?: string;
};

export type LoadingVariantsProps = VariantProps<typeof daisy_variants>;

export const Loading: Component<LoadingProps> = props => {
  const p = mergeProps({ variant: 'spinner' as const, size: 'sm' as const }, props);

  const isDaisy = () =>
    !['spinner-3', 'spinner-4', 'spinner-5', 'spinner-6'].includes(p.variant as string);

  const resolvedColor = () => resolveColor(p.color);
  const svgClass = () => cn(svg_size_map[p.size as SizeKey], p.class);

  return (
    <Switch>
      <Match when={isDaisy()}>
        <div
          class={cn(
            daisy_variants({
              variant: p.variant as DaisyVariant,
              size: p.size,
            }),
            p.class,
          )}
          style={resolvedColor() ? { color: resolvedColor() } : undefined}
        />
      </Match>
      <Match when={p.variant === 'spinner-3'}>
        <LoadingSpinner3 class={svgClass()} color={resolvedColor()} />
      </Match>
      <Match when={p.variant === 'spinner-4'}>
        <LoadingSpinner4 class={svgClass()} color={resolvedColor()} />
      </Match>
      <Match when={p.variant === 'spinner-5'}>
        <LoadingSpinner5 class={svgClass()} color={resolvedColor()} />
      </Match>
      <Match when={p.variant === 'spinner-6'}>
        <LoadingSpinner6 class={svgClass()} color={resolvedColor()} />
      </Match>
    </Switch>
  );
};
export const Spinner: Component<{ class?: string; color?: string }> = p => {
  const id = createUniqueId();

  p = mergeProps({ color: '#6E56CF' } as const, p);

  return (
    <div class={cn('size-3 animate-spin', p.class)}>
      <svg
        width="inherit"
        height="inherit"
        viewBox="0 0 20 20"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
      >
        <ellipse
          cx="9.99995"
          cy="9.99995"
          rx="7.31001"
          ry="7.31001"
          stroke={p.color}
          stroke-opacity="0.25"
          stroke-width="4"
        />
        <path
          d="M9.94939 2.69013C11.8881 2.67671 13.7527 3.43398 15.133 4.79535C16.5134 6.15671 17.2964 8.01067 17.3098 9.94936"
          stroke={`url(#${id})`}
          stroke-width="4"
          stroke-linecap="round"
          stroke-dasharray="1.23 1.23"
        />
        <defs>
          <linearGradient
            id={id}
            x1="16.3108"
            y1="13.6892"
            x2="3.68922"
            y2="6.31075"
            gradientUnits="userSpaceOnUse"
          >
            <stop stop-color={p.color} />
            <stop offset="0.5" stop-color={p.color} stop-opacity="0.01" />
            <stop offset="1" stop-color={p.color} stop-opacity="0" />
          </linearGradient>
        </defs>
      </svg>
    </div>
  );
};
